import org.junit.jupiter.api.Test;
import static org.junit.jupiter.api.Assertions.*;

public class SolutionTest {

    @Test
    void smallAdditive() {
        assertEquals("III", new Solution().intToRoman(3));
    }

    @Test
    void subtractiveIV() {
        assertEquals("IV", new Solution().intToRoman(4));
    }

    @Test
    void subtractiveIX() {
        assertEquals("IX", new Solution().intToRoman(9));
    }

    @Test
    void mixed() {
        assertEquals("LVIII", new Solution().intToRoman(58));
    }

    @Test
    void complexSubtractive() {
        assertEquals("MCMXCIV", new Solution().intToRoman(1994));
    }

    @Test
    void rangeMinimum() {
        assertEquals("I", new Solution().intToRoman(1));
    }

    @Test
    void rangeMaximum() {
        assertEquals("MMMCMXCIX", new Solution().intToRoman(3999));
    }
}
